export function getUrlProxyFromEnv(url?: string): {
  msg: string;
  proxyUrl: string | undefined;
} {
  let msg: string;
  let proxyUrl: string | undefined;

  const noProxy = process.env.no_proxy || process.env.NO_PROXY;
  if (url && `,${noProxy},`.includes(new URL(url).hostname)) {
    msg = `host in no_proxy/NO_PROXY`;
    proxyUrl = undefined;
    return { msg, proxyUrl };
  }

  if (process.env.https_proxy) {
    msg = `https_proxy`;
    proxyUrl = process.env.https_proxy;
    return { msg, proxyUrl };
  }

  if (process.env.HTTPS_PROXY) {
    msg = `HTTPS_PROXY`;
    proxyUrl = process.env.HTTPS_PROXY;
    return { msg, proxyUrl };
  }

  if (process.env.http_proxy) {
    msg = `http_proxy`;
    proxyUrl = process.env.http_proxy;
    return { msg, proxyUrl };
  }

  if (process.env.HTTP_PROXY) {
    msg = `HTTP_PROXY`;
    proxyUrl = process.env.HTTP_PROXY;
    return { msg, proxyUrl };
  }

  msg = `no PROXY defined`;
  proxyUrl = undefined;
  return { msg, proxyUrl };
}
